import{_ as a,o as e,c as r,ae as i}from"./chunks/framework.D_vkKrCz.js";const f=JSON.parse('{"title":"功能介绍","description":"","frontmatter":{"sidebar":true},"headers":[],"relativePath":"features.md","filePath":"features.md"}'),l={name:"features.md"};function d(o,t,h,n,s,u){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h1><p>IM²ODE经过十年持续迭代，已经成为功能全面的逆向材料设计平台，支持多维度、多类型的功能材料设计需求。</p><hr><h2 id="核心算法-多目标差分演化算法" tabindex="-1">核心算法：多目标差分演化算法 <a class="header-anchor" href="#核心算法-多目标差分演化算法" aria-label="Permalink to &quot;核心算法：多目标差分演化算法&quot;">​</a></h2><p>IM²ODE基于先进的多目标差分演化算法，结合第一性原理计算，能够高效筛选同时满足多个性能目标的最优材料结构，代码已开源托管于GitHub。</p><h3 id="算法优势" tabindex="-1">算法优势 <a class="header-anchor" href="#算法优势" aria-label="Permalink to &quot;算法优势&quot;">​</a></h3><ul><li>✅ 多目标同时优化，直接得到Pareto最优解集</li><li>✅ 高效去重机制，避免冗余计算</li><li>✅ 自适应变异策略，搜索效率提升300%</li><li>✅ 支持大规模并行计算，适配超算环境</li></ul><hr><h2 id="dfse专用模块-铁电材料设计" tabindex="-1">DFSE专用模块：铁电材料设计 <a class="header-anchor" href="#dfse专用模块-铁电材料设计" aria-label="Permalink to &quot;DFSE专用模块：铁电材料设计&quot;">​</a></h2><p>2025年新增DFSE（Differential Evolution for Ferroelectrics）专用模块，专为铁电功能材料设计优化，大幅提升铁电材料搜索效率与准确率。</p><h3 id="模块功能" tabindex="-1">模块功能 <a class="header-anchor" href="#模块功能" aria-label="Permalink to &quot;模块功能&quot;">​</a></h3><ul><li>✅ 自动识别铁电极化方向</li><li>✅ 精准计算铁电翻转能垒</li><li>✅ 高通量筛选高性能铁电候选结构</li><li>✅ 相关成果发表于《J. Chem. Theory Comput.》</li></ul><hr><h2 id="纳米带结构搜索模块" tabindex="-1">纳米带结构搜索模块 <a class="header-anchor" href="#纳米带结构搜索模块" aria-label="Permalink to &quot;纳米带结构搜索模块&quot;">​</a></h2><p>2023年新增纳米带结构专用搜索模块，支持一维纳米带、边缘重构结构的自动化预测，拓展了IM²ODE在低维纳米电子材料领域的应用能力。</p><h3 id="模块功能-1" tabindex="-1">模块功能 <a class="header-anchor" href="#模块功能-1" aria-label="Permalink to &quot;模块功能&quot;">​</a></h3><ul><li>✅ 支持锯齿型（Zigzag）、扶手椅型（Armchair）纳米带结构搜索</li><li>✅ 自动识别边缘重构模式</li><li>✅ 计算电子/输运性质</li><li>✅ 相关成果发表于《Solid State Commun.》</li></ul><hr><h2 id="全维度材料设计支持" tabindex="-1">全维度材料设计支持 <a class="header-anchor" href="#全维度材料设计支持" aria-label="Permalink to &quot;全维度材料设计支持&quot;">​</a></h2><p>IM²ODE覆盖所有维度的材料设计需求，从块体到低维结构全面支持：</p><table tabindex="0"><thead><tr><th>维度</th><th>材料类型</th><th>应用领域</th></tr></thead><tbody><tr><td>🧊 3D</td><td>块体晶体、晶界、缺陷</td><td>半导体、超硬材料、热电材料</td></tr><tr><td>📄 2D</td><td>层状材料、表面、界面</td><td>光电材料、催化材料、铁电材料</td></tr><tr><td>🧵 1D</td><td>纳米线、纳米带</td><td>自旋电子器件、光电器件</td></tr><tr><td>🔬 0D</td><td>团簇、点缺陷</td><td>量子材料、发光材料</td></tr></tbody></table>',21)])])}const b=a(l,[["render",d]]);export{f as __pageData,b as default};
